SELECT event_code, description, severity, category, recommended_action
FROM event_codes
WHERE event_code > 5000;

SELECT event_id, user_id
FROM security_events
WHERE op_code = 'error';

SELECT computer_name, status
FROM computers
ORDER BY computer_name ASC;

SELECT DISTINCT ec.description
FROM event_codes ec
JOIN security_events se ON ec.event_code = se.event_code;

SELECT DISTINCT security_events.user_id, security_events.event_id
FROM security_events
WHERE security_events.event_type != 0;

SELECT u.user_name 
FROM users u 
WHERE u.user_id NOT IN (
    SELECT se.user_id 
    FROM security_events se
);

SELECT event_code, event_type
FROM security_events
ORDER BY event_time ASC;

SELECT event_code, event_type, computer_name
FROM security_events
WHERE computer_name = 'anon_ComputerName_10';
